const query = ($json && $json.query) ? $json.query : {};
const period = String(query.period || '30d');

const periodMap = {
  '7d': 'LAST_7_DAYS',
  '30d': 'LAST_30_DAYS',
  '90d': 'LAST_90_DAYS',
};

const gaqlPeriod = periodMap[period] || 'LAST_30_DAYS';

return [{
  json: {
    managerCustomerId: '1234567890',
    clientCustomerId: '1234567890',
    query: `SELECT segments.date, metrics.clicks, metrics.impressions, metrics.cost_micros, metrics.conversions FROM campaign WHERE segments.date DURING ${gaqlPeriod}`
  }
}];

const items = $input.all();

const batches = items.flatMap((item) => {
  const payload = item.json;

  if (Array.isArray(payload)) {
    return payload;
  }

  return [payload];
});

const byDate = new Map();

for (const batch of batches) {
  const rows = Array.isArray(batch?.results) ? batch.results : [];

  for (const row of rows) {
    const date = row?.segments?.date || row?.segments_date || row?.date;
    if (!date) {
      continue;
    }

    const current = byDate.get(date) || {
      data: date,
      cliques: 0,
      impressoes: 0,
      custo: 0,
      conversoes: 0,
    };

    current.cliques += Number(row?.metrics?.clicks || 0);
    current.impressoes += Number(row?.metrics?.impressions || 0);
    current.custo += Number(row?.metrics?.costMicros || row?.metrics?.cost_micros || 0) / 1000000;
    current.conversoes += Number(row?.metrics?.conversions || 0);

    byDate.set(date, current);
  }
}

const output = Array.from(byDate.values())
  .sort((a, b) => String(a.data).localeCompare(String(b.data)))
  .map((item) => ({
    ...item,
    custo: Number(item.custo.toFixed(2)),
  }));

return [{ json: output }];

const items = $input.all();

const normalizeType = (value) => {
  const input = String(value || '').toLowerCase();
  if (input.includes('display')) return 'Display';
  if (input.includes('video') || input.includes('vídeo')) return 'Vídeo';
  if (input.includes('max') || input.includes('performance')) return 'PMax';
  return 'Pesquisa';
};

const normalizeStatus = (value) => {
  const input = String(value || '').toLowerCase();
  if (['enabled', 'active', 'ativa'].includes(input)) return 'Ativa';
  if (['limited', 'limitada'].includes(input)) return 'Limitada';
  return 'Pausada';
};

const campaigns = items.map((item, index) => {
  const row = item.json || {};

  const orcamentoMicros = Number(
    row?.campaignBudget?.amountMicros ||
    row?.campaign_budget?.amount_micros ||
    row?.budgetAmountMicros ||
    0
  );

  const custoMicros = Number(
    row?.metrics?.costMicros ||
    row?.metrics?.cost_micros ||
    0
  );

  return {
    id: String(row?.campaign?.id || row?.id || `campaign-${index + 1}`),
    nome: String(row?.campaign?.name || row?.name || `Campanha ${index + 1}`),
    tipo: normalizeType(row?.campaign?.advertisingChannelType || row?.advertisingChannelType || row?.type),
    status: normalizeStatus(row?.campaign?.status || row?.status),
    orcamento: Number((orcamentoMicros / 1000000).toFixed(2)),
    cliques: Number(row?.metrics?.clicks || row?.cliques || 0),
    impressoes: Number(row?.metrics?.impressions || row?.impressoes || 0),
    custo: Number((custoMicros / 1000000).toFixed(2)),
    conversoes: Number(row?.metrics?.conversions || row?.conversoes || 0),
  };
});

return [{ json: campaigns }];

const body = ($json && $json.body && typeof $json.body === 'object') ? $json.body : {};
const campaigns = Array.isArray(body.campaigns) ? body.campaigns : [];
const performance = Array.isArray(body.performance) ? body.performance : [];

const totalClicks = performance.reduce((acc, item) => acc + Number(item.cliques || 0), 0);
const totalConversions = performance.reduce((acc, item) => acc + Number(item.conversoes || 0), 0);
const totalCost = performance.reduce((acc, item) => acc + Number(item.custo || 0), 0);
const conversionRate = totalClicks > 0 ? (totalConversions / totalClicks) * 100 : 0;

const pausedCampaigns = campaigns.filter((item) => String(item.status || '').toLowerCase() === 'pausada');
const lowVolumeCampaigns = campaigns.filter((item) => Number(item.cliques || 0) < 300);

const insights = [];

if (conversionRate < 5) {
  insights.push({
    id: 'ins-1',
    titulo: 'Conversão abaixo da meta',
    recomendacao: 'Ajuste termos de pesquisa e inclua extensões para aumentar cliques qualificados.',
    impacto: 'ROI',
    prioridade: 'alta'
  });
}

if (totalCost > 4000) {
  insights.push({
    id: 'ins-2',
    titulo: 'Custo elevado no período',
    recomendacao: 'Redistribua orçamento para campanhas com maior taxa de conversão e menor CPC.',
    impacto: 'Orçamento',
    prioridade: 'media'
  });
}

if (pausedCampaigns.length > 0) {
  insights.push({
    id: 'ins-3',
    titulo: 'Campanhas pausadas detectadas',
    recomendacao: `Revise ${pausedCampaigns.length} campanha(s) pausada(s) para recuperar volume.`,
    impacto: 'Lances',
    prioridade: 'media'
  });
}

if (lowVolumeCampaigns.length > 0) {
  insights.push({
    id: 'ins-4',
    titulo: 'Baixo volume em parte das campanhas',
    recomendacao: 'Teste novos criativos e variações de público para ampliar alcance.',
    impacto: 'Criativos',
    prioridade: 'baixa'
  });
}

if (insights.length === 0) {
  insights.push({
    id: 'ins-default',
    titulo: 'Performance estável',
    recomendacao: 'Mantenha a estratégia e monitore variações de CPC e conversão semanalmente.',
    impacto: 'ROI',
    prioridade: 'baixa'
  });
}

return [{ json: insights }];
